#include "perimortem/core/perimortem.hpp"

using namespace Perimortem::Core;
using namespace Perimortem::Serialization;
using namespace Validation;

// A little over 1kb of text data generated by hand.
static constexpr auto base64_1kb =
    "T3ZlciBhIHRob3VzYW5kIGNoYXJhY3RlcnMgb2YgdGV4dCBjcmVhdGVkIGZvciBiYXNlNjQgZW"
    "5jb2RpbmcgLyBkZWNvZGluZyBiZW5jaG1hcmtpbmcuIENyZWF0ZSBhIHZhcmlldHkgb2YgZGF0"
    "YSBpbmNsdWRpbmcgZW1vamkgdmFsdWVzOiDinY7wn42J8J+NgSDwn42AIOKsh++"
    "4jyDwn5KVIPCfkoog8J+MtyDwn42VIPCfjrUg8J+ZjyDwn42LIPCfk4Ig4puxIPCfjrcg8J+"
    "OoyDwn4aYIPCfjJAg8J+UniDwn46BIPCfkZog8J+OhCDwn5K/"
    "IPCfjYouIEFkZGl0aW9uYWwgdGV4dCB0byBtYWtlIHN1cmUgZW5jb2RpbmcgaXNuJ3Qgc2NyYW"
    "1ibGVkIGFmdGVyIHRoZSBlbW9qaSBkYXRhLiBJbnNlcnRpbmcgZXZlbiBtb3JlIHJhbmRvbWx5"
    "IGdlbmVyYXRlZCBlbW9qaSB2YWx1ZXM6IPCfiLYg4pqWIPCfjZgg8J+Igu+4jyDwn4+"
    "dIPCfk4Qg8J+PtSDwn5K7IPCfkr0g8J+RgCDwn5ayIPCfjLgg8J+UrSDwn42fIPCflaQg8J+"
    "RjCDwn5i5IPCfmJog8J+PpiDijJrvuI8g8J+"
    "YgCDinYwuIEFuZCBub3cgZm9yIHNvbWUgamFwYW5lc2UgdGV4dCBhcyB3ZWxsOiDmmI7ml6Xjg"
    "a/"
    "mmI7ml6Xjga7poqjjgYzlkLnjgY8uIE51bWJlcnMgMTAwLCAzLjE0LCAtOTksIDIyLjIxLCAxM"
    "F45LiBQYWRkaW5nIG91dCB0aGUgZGF0YSB1bnRpbCB3ZSBoaXQgfjFrYiBvZiB0ZXN0IGRhdGE"
    "gZm9yIHZhcmlvdXMgc3RyaW5nIGZ1bmN0aW9ucy4gVGhpcyBjb3ZlcnMgVVRGLTggYXMgd2Vsb"
    "CB3aGljaCBpcyB1c2VmdWwgZnJvbSBzdHJpbmcgdGVzdHMuIDEyMzQ1Njc4OTAhQCMkJV4mKig"
    "pLT1hYmNkZWZnaGlqa2xtbm9wcXJzdHV2d3h5ekFCQ0RFRkdISUpLTE1OT1BRUlNUVVZXWFlae"
    "g=="_view;

static constexpr auto source_1kb =
    "Over a thousand characters of text created for base64 encoding / decoding "
    "benchmarking. Create a variety of data including emoji values: ❎🍉🍁 🍀 "
    "⬇️ 💕 💊 🌷 🍕 🎵 🙏 🍋 📂 ⛱ 🎷 🎣 🆘 🌐 🔞 🎁 👚 🎄 💿 🍊. Additional "
    "text to make sure encoding isn't scrambled after the emoji data. "
    "Inserting even more randomly generated emoji values: 🈶 ⚖ 🍘 🈂️ 🏝 📄 🏵 "
    "💻 💽 👀 🖲 🌸 🔭 🍟 🕤 👌 😹 😚 🏦 ⌚️ 😀 ❌. And now for some japanese "
    "text as well: 明日は明日の風が吹く. Numbers 100, 3.14, -99, 22.21, 10^9. "
    "Padding out the data until we hit ~1kb of test data for various string "
    "functions. This covers UTF-8 as well which is useful from string tests. "
    "1234567890!@#$%^&*()-="
    "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZz"_view;

static constexpr Count batch_count = 1024;

static Harness Base64Bench = {
  .name = "Base64"_view,
};

PERIMORTEM_BENCHMARK(Base64Bench, decode_1k_bytes) {
  Count size = 0;

  for (Count i = 0; i < batch_count; i++) {
    auto decoded = Base64::decode(base64_1kb);
    size += decoded.get_size();
  }

  Benchmark::prevent_optimization(size);
}

PERIMORTEM_BENCHMARK(Base64Bench, encode_1k_bytes) {
  Count size = 0;

  for (Count i = 0; i < batch_count; i++) {
    auto encode = Base64::decode(source_1kb);
    size += encode.get_size();
  }

  Benchmark::prevent_optimization(size);
}
